Kaj izpiše naslednji program? 
class Izpis { 
  static int m(int i) { 
    System.out.print(i + ", ");  
    return i; 
  } 
  public static void main(String s[]) { 
    int i = 1;  
    m(m(++i) + m(i++) + m(-i) + m(i++)); 
  } 
} 
