class Besedilo { 
  static void m1(String s1) { 
    s1.replace('A','Y'); System.out.print(s1); 
  } 
  static void m2(String s1) { 
    s1 = s1.replace('A','Z'); System.out.print(s1); 
  } 
  public static void main(String[] s) { 
    String s1 = "A";  
    m1(s1);  
    m2(s1); 
    System.out.print(s1); 
  } 
} 
